/* eslint-disable @next/next/no-img-element */
"use client";

import { Minus, Plus, Trash2 } from "lucide-react";
import Link from "next/link";

import { useStorefront } from "@/components/providers/StorefrontProvider";
import { formatIQD, getProductName } from "@/lib/storefront";
import { useCartStore } from "@/store/cart";

export function CartView() {
  const { language, isRTL, t } = useStorefront();
  const { items, totalItems, totalIQD, updateQuantity, removeItem, clearCart } =
    useCartStore();

  if (items.length === 0) {
    return (
      <div className="surface-card flex flex-col items-center justify-center gap-4 px-6 py-14 text-center">
        <p className="text-lg font-semibold text-slate-900">{t("cart.empty")}</p>
        <Link
          href="/products"
          className="rounded-2xl bg-primary px-5 py-3 text-sm font-semibold text-white transition hover:bg-[#256a2a]"
        >
          {t("cart.continueShopping")}
        </Link>
      </div>
    );
  }

  return (
    <div className="grid gap-6 lg:grid-cols-[1.5fr_0.9fr]">
      <div className="space-y-4">
        {items.map((item) => (
          <article
            key={item.product.id}
            className="surface-card flex flex-col gap-4 p-5 sm:flex-row sm:items-center"
          >
            <img
              src={item.product.image_url}
              alt={getProductName(item.product, language)}
              className="h-28 w-28 rounded-[1.5rem] bg-[#f7fbf7] object-contain p-4"
            />

            <div className={isRTL ? "sm:text-right" : "sm:text-left"}>
              <Link
                href={`/product/${item.product.id}`}
                className="text-lg font-semibold text-slate-900 transition hover:text-primary"
              >
                {getProductName(item.product, language)}
              </Link>
              <p className="mt-2 text-sm text-slate-500">
                {formatIQD(item.product.price_iqd, language)}
              </p>
            </div>

            <div
              className={`flex flex-1 items-center justify-between gap-4 sm:justify-end ${
                isRTL ? "sm:flex-row-reverse" : ""
              }`}
            >
              <div className="inline-flex items-center gap-2 rounded-2xl border border-emerald-100 bg-[#f7fbf7] p-1">
                <button
                  type="button"
                  onClick={() => updateQuantity(item.product.id, item.quantity - 1)}
                  className="inline-flex h-10 w-10 items-center justify-center rounded-xl bg-white text-slate-700 transition hover:text-primary"
                  aria-label="Decrease"
                >
                  <Minus size={16} />
                </button>
                <span className="min-w-10 text-center text-sm font-semibold text-slate-900">
                  {item.quantity}
                </span>
                <button
                  type="button"
                  onClick={() => updateQuantity(item.product.id, item.quantity + 1)}
                  className="inline-flex h-10 w-10 items-center justify-center rounded-xl bg-white text-slate-700 transition hover:text-primary"
                  aria-label="Increase"
                >
                  <Plus size={16} />
                </button>
              </div>

              <button
                type="button"
                onClick={() => removeItem(item.product.id)}
                className="inline-flex h-11 w-11 items-center justify-center rounded-2xl border border-rose-100 bg-rose-50 text-danger transition hover:border-danger"
                aria-label={t("cart.remove")}
              >
                <Trash2 size={16} />
              </button>
            </div>
          </article>
        ))}
      </div>

      <aside className="surface-card h-fit space-y-4 p-6">
        <div className={isRTL ? "text-right" : "text-left"}>
          <h2 className="text-lg font-semibold text-slate-900">
            {t("cart.summary")}
          </h2>
          <div className="mt-4 grid gap-3 text-sm text-slate-600">
            <div className="flex items-center justify-between">
              <span>{t("cart.totalItems")}</span>
              <span className="font-semibold text-slate-900">{totalItems}</span>
            </div>
            <div className="flex items-center justify-between border-t border-emerald-50 pt-3">
              <span>{t("cart.totalAmount")}</span>
              <span className="text-base font-bold text-primary">
                {formatIQD(totalIQD, language)}
              </span>
            </div>
          </div>
        </div>

        <div className="grid gap-3">
          <Link
            href="/checkout"
            className="rounded-2xl bg-primary px-5 py-3 text-center text-sm font-semibold text-white transition hover:bg-[#256a2a]"
          >
            {t("cart.checkout")}
          </Link>
          <button
            type="button"
            onClick={() => clearCart()}
            className="rounded-2xl border border-emerald-100 bg-white px-5 py-3 text-sm font-semibold text-slate-700 transition hover:border-primary hover:text-primary"
          >
            {t("cart.clear")}
          </button>
        </div>
      </aside>
    </div>
  );
}
